import{c as t,Q as o,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Privacy boundary","description":"Who sees what — operator, LLM, agent, you, the chain.","frontmatter":{"title":"Privacy boundary","description":"Who sees what — operator, LLM, agent, you, the chain."},"headers":[],"relativePath":"get-started/privacy-boundary.md","filePath":"get-started/privacy-boundary.md","lastUpdated":1780245214000}'),s={name:"get-started/privacy-boundary.md"};function n(i,e,l,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="privacy-boundary" tabindex="-1">Privacy boundary <a class="header-anchor" href="#privacy-boundary" aria-label="Permalink to &quot;Privacy boundary&quot;">​</a></h1><p>MuHaven encrypts balances end-to-end with Fully Homomorphic Encryption (Fhenix CoFHE). But &quot;end-to-end&quot; is fuzzy — different surfaces have different visibility. This page is the single source of truth on <strong>who sees what</strong>.</p><h2 id="the-five-observers" tabindex="-1">The five observers <a class="header-anchor" href="#the-five-observers" aria-label="Permalink to &quot;The five observers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Observer</th><th>What they see</th></tr></thead><tbody><tr><td><strong>The chain</strong> (Arbitrum)</td><td>Encrypted handles (<code>euint128</code>, <code>euint64</code>). Public addresses. Public NAVs. Aggregate event counts.</td></tr><tr><td><strong>The operator</strong> (MuHaven&#39;s backend)</td><td>Aggregate event counts. Issuer KYB metadata. Audit log rows. Public NAVs and yields. <strong>Never</strong> cleartext balances.</td></tr><tr><td><strong>The LLM</strong> (HavenBot&#39;s Gemini / your MCP host&#39;s Claude / etc.)</td><td>The structured-tool-call inputs and outputs the backend chooses to return. Encrypted-handle stubs, <strong>never</strong> cleartext.</td></tr><tr><td><strong>The agent</strong> (the tool runner)</td><td>Plaintext for the tool calls you authorized. Decrypted previews assembled in your browser via local permits.</td></tr><tr><td><strong>You</strong></td><td>Everything you ask for. Your encrypted balances unsealed locally via <code>decryptForView</code> + permit.</td></tr></tbody></table><h2 id="where-the-encryption-actually-lives" tabindex="-1">Where the encryption actually lives <a class="header-anchor" href="#where-the-encryption-actually-lives" aria-label="Permalink to &quot;Where the encryption actually lives&quot;">​</a></h2><p><strong>Encrypted on-chain (FHE ciphertext):</strong></p><ul><li>Per-investor token balances (<code>MuHavenToken</code> <code>_balances</code>).</li><li>Per-investor yield-claim amounts (in <code>MuHavenEscrow</code> redeemed flag + payout handle).</li><li>Risk-parameter thresholds (<code>RiskParams.sol</code> <code>_maxDrawdown</code>, <code>_dailySpent</code>, <code>_maxDailySpend</code>).</li><li>Encrypted votes (<code>EncryptedGovernance.castVote</code>).</li></ul><p><strong>Plaintext on-chain (public):</strong></p><ul><li>Wallet addresses.</li><li>Token NAVs (deviation-gated oracle writes by the issuer).</li><li>KYC whitelist membership (boolean per address).</li><li>Aggregate token addresses and event topics.</li></ul><p><strong>Plaintext on the operator&#39;s backend:</strong></p><ul><li>Audit log rows (one per agent action) — surface, tool, timestamp, outcome.</li><li>Issuer onboarding metadata (legal name, jurisdiction).</li><li>HavenBot chat history (server-managed; you can clear it).</li><li>Aggregate counts that drive the public metrics page.</li></ul><p><strong>Plaintext in your browser only:</strong></p><ul><li>The decrypted preview you see in ConfirmModal before signing.</li><li>Any <code>decryptForView(handle).withPermit().execute()</code> result.</li><li>Your passkey assertion at sign-in.</li></ul><h2 id="what-the-operator-never-sees-cleartext-balances-means" tabindex="-1">What &quot;the operator never sees cleartext balances&quot; means <a class="header-anchor" href="#what-the-operator-never-sees-cleartext-balances-means" aria-label="Permalink to &quot;What &quot;the operator never sees cleartext balances&quot; means&quot;">​</a></h2><p>The MuHaven backend handles:</p><ul><li>Routing your tool calls to the right contract / SDK method.</li><li>Stamping audit log rows.</li><li>Writing public NAVs as the issuer.</li><li>Running the policy-engine cron tick (which uses <em>encrypted</em> inputs end-to-end). This is the Policy-bound design; the encrypted-threshold engine is built but disabled in every deployment today, so this tick does not auto-sign.</li></ul><p>It does <strong>not</strong> decrypt FHE handles. The FHE decrypt pipeline is:</p><ol><li>You hold a permit signed by your MuHaven wallet (<code>cofheClient.getOrCreateSelfPermit()</code>).</li><li>Your browser calls <code>cofheClient.decryptForView(handle).withPermit().execute()</code>.</li><li>The CoFHE threshold network checks the permit&#39;s ACL on-chain, returns cleartext <strong>to you</strong>.</li><li>The backend is not involved in this path.</li></ol><p>There&#39;s one narrow exception in the Policy-bound design: the policy-engine breach path would emit a one-time <code>decryptForTx</code> <em>of the breach event itself</em> so a <code>RiskBreach</code> can be settled on-chain. The breach event surfaces &quot;your tier auto-paused; here&#39;s a generic reason code&quot;; it does <strong>not</strong> decrypt the underlying balance. (This breach path is part of the disabled Policy-bound engine — it is present in the contracts but not driven in any deployment today.)</p><h2 id="what-the-llm-sees" tabindex="-1">What the LLM sees <a class="header-anchor" href="#what-the-llm-sees" aria-label="Permalink to &quot;What the LLM sees&quot;">​</a></h2><p>This depends on which surface:</p><table tabindex="0"><thead><tr><th>Surface</th><th>LLM model</th><th>LLM sees</th></tr></thead><tbody><tr><td><strong>HavenBot</strong></td><td>Google Gemini</td><td>The chat transcript + structured tool inputs/outputs returned by the backend. <strong>Never</strong> raw FHE handles.</td></tr><tr><td><strong><code>@muhaven/mcp</code></strong></td><td>Whatever you installed (Claude / etc.)</td><td>Same as HavenBot: the JSON the MCP tools return.</td></tr><tr><td><strong>OpenClaw + Telegram</strong></td><td>No LLM at the bot edge — Telegram messages are deterministic templates</td><td>The bot sees your Telegram chat ID + the inline button you tapped. No LLM exposure.</td></tr><tr><td><strong>Hosted Checkout</strong></td><td>No LLM</td><td>The buyer sees a deterministic checkout page.</td></tr></tbody></table><p>In every case, the LLM-side context is a <strong>window into the backend&#39;s response</strong>, not a window into your encrypted state. The MCP server in particular <strong>never</strong> decrypts — it returns aggregates and structured envelopes.</p><div class="tip custom-block"><p class="custom-block-title">Read tools are intentionally non-auditing</p><p>We don&#39;t log every &quot;user looked at portfolio&quot; call. Only <strong>propose</strong> and <strong>commit</strong> events emit audit rows. Read-side privacy is the floor; forensic completeness for state-changing actions is the wall.</p></div><h2 id="what-the-policy-gate-sees" tabindex="-1">What the policy gate sees <a class="header-anchor" href="#what-the-policy-gate-sees" aria-label="Permalink to &quot;What the policy gate sees&quot;">​</a></h2><p>The policy gate runs <strong>deterministic</strong> code — no LLM in the signing path. It sees:</p><ul><li>The structured tool intent emitted by the LLM (a JSON object with strict-enum fields).</li><li>Your current tier and session-key scope.</li><li>The encrypted threshold check via <code>RiskParams.checkAndExecute(eAmount, action)</code>.</li></ul><p>It does <strong>not</strong> see cleartext amounts (the FHE check is on ciphertext). It rejects intents that don&#39;t match its allowlist; rejected intents never reach a signer.</p><p>This is the <strong>CaMeL planner/action split</strong> — the LLM plans, the gate disposes. A jailbroken LLM cannot exfiltrate value because the gate is deterministic code and does not consult the LLM about whether to sign.</p><h2 id="what-s-leaked-at-the-edges" tabindex="-1">What&#39;s leaked at the edges <a class="header-anchor" href="#what-s-leaked-at-the-edges" aria-label="Permalink to &quot;What&#39;s leaked at the edges&quot;">​</a></h2><p>No system is leakage-free. Two known side-channels worth being aware of:</p><ol><li><strong>Wrap-to-mhUSDC deposit size</strong> leaks at the moment of wrap to a chain observer.</li><li><strong>Decrypt-event timing</strong> for breach-path <code>decryptForTx</code> calls would correlate decrypt frequency to swap frequency if not for the <strong>branchless <code>FHE.select</code> hot path</strong> — decrypts are kept off the policy hot path precisely to avoid this.</li></ol><h2 id="comparison-zk-vs-tee-vs-mpc-vs-fhe" tabindex="-1">Comparison: ZK vs TEE vs MPC vs FHE <a class="header-anchor" href="#comparison-zk-vs-tee-vs-mpc-vs-fhe" aria-label="Permalink to &quot;Comparison: ZK vs TEE vs MPC vs FHE&quot;">​</a></h2><p>MuHaven chose FHE; here&#39;s the trade-space in one paragraph.</p><ul><li><strong>ZK</strong> (zero-knowledge): great for proving statements, awkward for stateful balances. State of the art (Aztec, Aleo) requires application-specific circuits.</li><li><strong>TEE</strong> (trusted execution): cheap per-op, requires trust in the silicon vendor (Intel SGX, AMD SEV). Side-channel attacks (CacheBleed, etc.) are an active research area.</li><li><strong>MPC</strong> (multi-party computation): no single-party trust, but high coordination cost and slow for general computation.</li><li><strong>FHE</strong>: computation on ciphertext directly; no per-op trust assumption; slowest of the four today but improving fast (Fhenix CoFHE TFHE-rs target: 50× per quarter for the next two years).</li></ul><p>MuHaven leans on FHE because the <strong>stateful encrypted-balance</strong> primitive is exactly what FHE is uniquely good at, and the side-channel surface is smaller than TEE&#39;s.</p><h2 id="where-to-read-more" tabindex="-1">Where to read more <a class="header-anchor" href="#where-to-read-more" aria-label="Permalink to &quot;Where to read more&quot;">​</a></h2><ul><li><a href="https://github.com/hasToDev/muhaven/blob/master/docs/THREAT_MODEL.md" target="_blank" rel="noreferrer"><code>docs/THREAT_MODEL.md</code></a> — full project-level threat model.</li><li><a href="https://github.com/hasToDev/muhaven/blob/master/docs/AGENT_DESIGN.md" target="_blank" rel="noreferrer"><code>docs/AGENT_DESIGN.md</code></a> — agent-layer architecture.</li><li><a href="/policy/tiered-autonomy">Tiered autonomy</a> — how the policy gate enforces what the agent can do.</li></ul>',38)])])}const g=t(s,[["render",n]]);export{p as __pageData,g as default};
